import ast, subprocess, sys

def strip_docstrings(src):
    tree = ast.parse(src)
    for node in ast.walk(tree):
        if isinstance(node, (ast.Module, ast.ClassDef, ast.FunctionDef, ast.AsyncFunctionDef)):
            body = node.body
            if body and isinstance(body[0], ast.Expr) and isinstance(getattr(body[0], 'value', None), ast.Constant) and isinstance(body[0].value.value, str):
                node.body = body[1:] if len(body) > 1 else [ast.Pass()]
    return ast.dump(tree)

files = subprocess.check_output(["git","diff","--name-only","src/"], text=True).split()
allpass = True
for f in files:
    work = open(f, encoding="utf-8").read()
    head = subprocess.check_output(["git","show",f"HEAD:{f}"], text=True)
    try:
        w = strip_docstrings(work); h = strip_docstrings(head)
    except SyntaxError as e:
        print(f"PARSE-FAIL {f}: {e}"); allpass=False; continue
    ok = (w == h)
    if not ok: allpass=False
    print(f"{'PASS' if ok else 'FAIL'} {f}")
print("ALL_PASS" if allpass else "SOME_FAIL")
sys.exit(0 if allpass else 1)
